// ============================================================
// Binary search — ITERATIVE version
// ============================================================
// Loop instead of recursion. O(log n) time, O(1) space.

function binarySearchIterative(arr, target) {
  let lo = 0;
  let hi = arr.length - 1;

  while (lo <= hi) {
    // Avoid (lo + hi) / 2 — can overflow in other languages.
    // In JS the safer expression is lo + Math.floor((hi - lo) / 2).
    const mid = lo + Math.floor((hi - lo) / 2);

    if (arr[mid] === target) return mid;
    if (arr[mid] <  target) lo = mid + 1;  // throw away left half
    else                    hi = mid - 1;  // throw away right half
  }
  return -1;  // not found
}

const data = [3, 7, 12, 18, 23, 31, 47, 56, 71, 89];
console.log('found 23 at index:', binarySearchIterative(data, 23));   // 4
console.log('found 89 at index:', binarySearchIterative(data, 89));   // 9
console.log('found 99 at index:', binarySearchIterative(data, 99));   // -1
console.log('found 3  at index:', binarySearchIterative(data, 3));    // 0

// ============================================================
// Binary search — RECURSIVE version
// ============================================================
// O(log n) time, O(log n) space (recursion stack).
//
// The recursion is 'tail-like' — we recurse exactly once per level.
// Each call shrinks the [lo..hi] window by half.

function binarySearchRecursive(arr, target, lo = 0, hi = arr.length - 1) {
  // Base case: window is empty → not found
  if (lo > hi) return -1;

  const mid = lo + Math.floor((hi - lo) / 2);

  if (arr[mid] === target) return mid;

  if (arr[mid] < target) {
    // Search right half
    return binarySearchRecursive(arr, target, mid + 1, hi);
  } else {
    // Search left half
    return binarySearchRecursive(arr, target, lo, mid - 1);
  }
}

const data = [3, 7, 12, 18, 23, 31, 47, 56, 71, 89];
console.log('found 23 at index:', binarySearchRecursive(data, 23));   // 4
console.log('found 99 at index:', binarySearchRecursive(data, 99));   // -1

// Both versions return identical results.
// Prefer iterative when possible — no stack overflow risk.

// Where do you find O(log n) in real code?
//
// 1. Binary search (shown above)
// 2. Operations on balanced binary search trees (insert, delete, find)
// 3. Heap insert/extract (priority queues)
// 4. Recursing by halving — divide-and-conquer like exponentiation

// Fast exponentiation: a^n in O(log n) instead of O(n).
// Idea: a^10 = (a^5)² = (a · a^4)² = ...
function power(a, n) {
  if (n === 0) return 1;
  const half = power(a, Math.floor(n / 2));
  if (n % 2 === 0) return half * half;
  else             return half * half * a;
}

console.log('2^10 =', power(2, 10));     // 1024
console.log('2^20 =', power(2, 20));     // 1,048,576
console.log('3^15 =', power(3, 15));     // 14,348,907

// Each recursive call halves n. log₂(20) ≈ 4 calls for 2^20.

